parameters.jsonBody:
={{
  JSON.stringify({
    model: 'dall-e-3',
    prompt: 'Create a visually stunning social media post image about: ' + $json.topic + '. Style: ' + $json.style + '. The image should be eye-catching, suitable for Instagram feed, square aspect ratio, no text overlays.',
    n: 1,
    size: '1024x1024',
    quality: 'hd'
  })
}}

={{
  JSON.stringify({
    model: 'gpt-4o',
    messages: [
      {
        role: 'system',
        content: 'You are an expert social media copywriter for Instagram. Generate engaging captions and relevant hashtags. Respond ONLY with valid JSON in this exact format: {"caption": "...", "hashtags": "..."}. The caption should be 2-4 sentences, engaging, and match the brand voice. Include 15-25 relevant hashtags as a single string separated by spaces, each starting with #. No markdown, no extra text.'
      },
      {
        role: 'user',
        content: 'Write an Instagram caption and hashtags for a post about: ' + $json.topic + '. Brand voice: ' + $json.brand_voice + '.'
      }
    ],
    temperature: 0.8,
    max_tokens: 500
  })
}}

parameters.jsonOutput:
={{
  const imgData = $('Generate Image (DALL-E 3)').first().json;
  const gptData = $('Generate Caption & Hashtags (GPT)').first().json;
  const imageUrl = imgData.data[0].url;
  const gptContent = JSON.parse(gptData.choices[0].message.content);

  return JSON.stringify({
    imageUrl: imageUrl,
    revisedPrompt: imgData.data[0].revised_prompt || '',
    caption: gptContent.caption,
    hashtags: gptContent.hashtags,
    fullCaption: gptContent.caption + '\n\n' + gptContent.hashtags
  })
}}

={{
  JSON.stringify({
    success: true,
    instagramPostId: $json.id,
    caption: $('Merge Image + Caption').first().json.fullCaption,
    imageUrl: $('Merge Image + Caption').first().json.imageUrl,
    timestamp: new Date().toISOString()
  })
}}
